import React, { useRef, useEffect } from 'react';

const InputArea = ({ 
  inputMessage, 
  setInputMessage, 
  onSendMessage, 
  isLoading, 
  theme,
  placeholder = "Ask me anything about programming, math, science, or any subject! 🚀"
}) => {
  const textareaRef = useRef(null);

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      if (inputMessage.trim() && !isLoading) {
        onSendMessage();
      }
    }
  };

  const handleInputChange = (e) => {
    setInputMessage(e.target.value);
    autoResize();
  };

  const autoResize = () => {
    const textarea = textareaRef.current;
    if (textarea) {
      textarea.style.height = 'auto';
      const newHeight = Math.min(textarea.scrollHeight, 120);
      textarea.style.height = newHeight + 'px';
    }
  };

  useEffect(() => {
    autoResize();
  }, [inputMessage]);

  useEffect(() => {
    // Focus input when component mounts (optional)
    const textarea = textareaRef.current;
    if (textarea && !isLoading) {
      textarea.focus();
    }
  }, [isLoading]);

  const handleSubmit = (e) => {
    e.preventDefault();
    if (inputMessage.trim() && !isLoading) {
      onSendMessage();
    }
  };

  return (
    <div className={`input-area ${theme}`}>
      <div className="input-container">
        <div className="input-wrapper">
          <textarea
            ref={textareaRef}
            className="message-input"
            placeholder={placeholder}
            value={inputMessage}
            onChange={handleInputChange}
            onKeyPress={handleKeyPress}
            disabled={isLoading}
            rows="1"
            maxLength={2000}
            aria-label="Type your message"
          />
          
          {/* Character count indicator */}
          {inputMessage.length > 1800 && (
            <div className="char-count">
              {inputMessage.length}/2000
            </div>
          )}
          
          <button
            className={`send-btn ${inputMessage.trim() ? 'active' : ''}`}
            onClick={handleSubmit}
            disabled={isLoading || !inputMessage.trim()}
            title={isLoading ? 'Sending...' : 'Send message (Enter)'}
            aria-label="Send message"
          >
            {isLoading ? (
              <div className="loading-spinner">
                <div className="spinner" />
              </div>
            ) : (
              <span className="send-icon">🚀</span>
            )}
          </button>
        </div>
      </div>

      {/* Input footer with hints */}
      <div className="input-footer">
        <span className="input-hint">
          Press <kbd>Enter</kbd> to send • <kbd>Shift + Enter</kbd> for new line
          {inputMessage.length > 0 && ` • ${inputMessage.length} characters`}
        </span>
      </div>
    </div>
  );
};

export default InputArea;
